SELECT /*RequestReviewMapper.selectUsimRequestReviewTotalCnt 개통후기 리스트용 COUNT  */
    COUNT(1) AS CNT
FROM MCP_REQUEST_REVIEW
WHERE 1=1

        AND REQ_BUY_TYPE = #{reqBuyType}


        AND STTUS_VAL = #{sttusVal}


        AND COMMEND_YN = #{commendYn}


        AND EVENT_CD = #{eventCd}


        AND NTF_YN = #{ntfYn}


        AND RATE_CD = #{rateCd}



             AND REVIEW_SBST LIKE '%' || UPPER(#{searchValue}) || '%'


            AND REG_NM LIKE '%' || UPPER(#{searchValue}) || '%'


            AND PRIZE_SBST LIKE '%' || UPPER(#{searchValue}) || '%'



        AND REQUEST_KEY = #{requestKey}


         AND CONTRACT_NUM IN

                #{item}



        AND CONTRACT_NUM = #{contractNum}


        AND PROD_ID = #{prodId}


        AND LAST_BEST_REVIEW_CHK = 'Y'


        AND SNS_INFO IS NOT NULL


       AND TRUNC(SYSDATE) - TO_DATE(SYS_RDATE_DD, 'YYYYMMDD') < 90

SELECT /*RequestReviewMapper.selectUsimRequestReviewList 개통후기 리스트 */ REQUEST_KEY , CONTRACT_NUM , REQ_BUY_TYPE , MODEL_ID , PROD_ID , REVIEW_SBST , COMMEND_YN , EVENT_CD , SNS_INFO , NTF_YN , PRIZE_SBST , STTUS_VAL , RIP , SYS_RDATE , SYS_RDATE_DD , REG_NM , PROD_DIV_CD , REQ_BUY_PROD_MSN , RATE_CD , DECODE(REQ_BUY_TYPE,'UU','유심 후기','MM','휴대폰 후기','-') AS REQ_BUY_TYPE_NM , ADD_MONTHS(SYSDATE,-3) AS baseDate , REVIEW_ID FROM MCP_REQUEST_REVIEW WHERE 1=1
AND REQ_BUY_TYPE = #{reqBuyType}
AND STTUS_VAL = #{sttusVal}
AND COMMEND_YN = #{commendYn}
AND EVENT_CD = #{eventCd}
AND NTF_YN = #{ntfYn}
AND RATE_CD = #{rateCd}
AND REVIEW_SBST LIKE '%' || UPPER(#{searchValue}) || '%'
AND REG_NM LIKE '%' || UPPER(#{searchValue}) || '%'
AND PRIZE_SBST LIKE '%' || UPPER(#{searchValue}) || '%'
AND REQUEST_KEY = #{requestKey}
ORDER BY NTF_YN DESC, SYS_RDATE DESC

SELECT /*RequestReviewMapper.selectUsimRequestReviewImgList 개통후기 리스트 이미지 */ REQUEST_KEY , IMD_SEQ , FILE_PATH_NM , FILE_TYPE , FILE_CAPA , FILE_ALT , REVIEW_ID FROM MCP_REQUEST_REVIEW_IMG WHERE REQUEST_KEY = #{requestKey} AND REVIEW_ID = #{reviewId}
AND IMD_SEQ = #{imdSeq}
ORDER BY IMD_SEQ

