INSERT INTO MCP_REQUEST_REVIEW
(
    REQUEST_KEY
    , CONTRACT_NUM
    , REQ_BUY_TYPE
    , MODEL_ID
    , PROD_ID
    , REVIEW_SBST
    , COMMEND_YN
    , EVENT_CD
    , SNS_INFO
    , NTF_YN
    , PRIZE_SBST
    , STTUS_VAL
    , RIP
    , SYS_RDATE
    , SYS_RDATE_DD
    , REG_NM
    , PROD_DIV_CD
    , REQ_BUY_PROD_MSN
    , RATE_CD
    , HIT_CNT
    , REVIEW_ID
) VALUES (

    #{requestKey}
    , #{contractNum}
    , #{reqBuyType}
    , #{modelId}
    , #{prodId}
    , #{reviewSbst}
    , #{commendYn}
    , #{eventCd}
    , #{snsInfo}
    , #{ntfYn}
    , #{prizeSbst}
    , #{sttusVal}
    , #{rIP}
    , SYSDATE
    , TO_CHAR(SYSDATE,'YYYYMMDD')
    , #{regNm}
    , #{prodDivCd}
    , #{reqBuyProdMsn}
    , #{rateCd}
    , NVL(#{hitCnt}, 0)
    , MCP_REQUEST_REVIEW_SEQ.NEXTVAL
)

INSERT INTO MCP_REQUEST_REVIEW_IMG
(
    REQUEST_KEY
    , IMD_SEQ
    , FILE_PATH_NM
    , FILE_TYPE
    , FILE_CAPA
