mapper.select:
SELECT /*RequestReviewMapper.selectRequestReviewList 개통후기 리스트 */ a.REQUEST_KEY , a.CONTRACT_NUM , a.REQ_BUY_TYPE , a.MODEL_ID , a.PROD_ID , a.REVIEW_SBST , a.COMMEND_YN , a.EVENT_CD , a.SNS_INFO , a.NTF_YN , a.PRIZE_SBST , a.STTUS_VAL , a.RIP , a.SYS_RDATE , a.SYS_RDATE_DD , a.REG_NM , a.PROD_DIV_CD , a.REQ_BUY_PROD_MSN , a.RATE_CD , a.HIT_CNT , a.REQ_BUY_TYPE_NM , a.RANKING , ADD_MONTHS(SYSDATE,-3) AS baseDate , LAST_BEST_REVIEW_CHK , a.REVIEW_ID FROM( SELECT REQUEST_KEY , CONTRACT_NUM , REQ_BUY_TYPE , MODEL_ID , PROD_ID , REVIEW_SBST , COMMEND_YN , EVENT_CD , SNS_INFO , NTF_YN , PRIZE_SBST , STTUS_VAL , RIP , SYS_RDATE , SYS_RDATE_DD , REG_NM , PROD_DIV_CD , REQ_BUY_PROD_MSN , RATE_CD , HIT_CNT , DECODE(REQ_BUY_TYPE,'UU','유심 후기','MM','휴대폰 후기','-') AS REQ_BUY_TYPE_NM , RANK() OVER(ORDER BY HIT_CNT DESC) RANKING , LAST_BEST_REVIEW_CHK , REVIEW_ID FROM MCP_REQUEST_REVIEW ) a WHERE NTF_YN = '1' AND STTUS_VAL = 1
AND REQ_BUY_TYPE = #{reqBuyType}
AND COMMEND_YN = #{commendYn}
AND EVENT_CD = #{eventCd}
AND CONTRACT_NUM IN
#{item}
AND PROD_ID = #{prodId}
AND RATE_CD = #{rateCd}
AND LAST_BEST_REVIEW_CHK = 'Y'
AND SNS_INFO IS NOT NULL
UNION ALL
SELECT c.REQUEST_KEY , c.CONTRACT_NUM , c.REQ_BUY_TYPE , c.MODEL_ID , c.PROD_ID , c.REVIEW_SBST , c.COMMEND_YN , c.EVENT_CD , c.SNS_INFO , c.NTF_YN , c.PRIZE_SBST , c.STTUS_VAL , c.RIP , c.SYS_RDATE , c.SYS_RDATE_DD , c.REG_NM , c.PROD_DIV_CD , c.REQ_BUY_PROD_MSN , c.RATE_CD , c.HIT_CNT , c.REQ_BUY_TYPE_NM , c.RANKING , ADD_MONTHS(SYSDATE,-3) AS baseDate , c.LAST_BEST_REVIEW_CHK , c.REVIEW_ID FROM( SELECT /*RequestReviewMapper.selectUsimRequestReviewList 개통후기 리스트 */ REQUEST_KEY , CONTRACT_NUM , REQ_BUY_TYPE , MODEL_ID , PROD_ID , REVIEW_SBST , COMMEND_YN , EVENT_CD , SNS_INFO , NTF_YN , PRIZE_SBST , STTUS_VAL , RIP , SYS_RDATE , SYS_RDATE_DD , REG_NM , PROD_DIV_CD , REQ_BUY_PROD_MSN , RATE_CD , HIT_CNT , DECODE(REQ_BUY_TYPE,'UU','유심 후기','MM','휴대폰 후기','-') AS REQ_BUY_TYPE_NM , RANK() OVER(ORDER BY HIT_CNT DESC) RANKING , LAST_BEST_REVIEW_CHK , REVIEW_ID FROM MCP_REQUEST_REVIEW ORDER BY SYS_RDATE DESC ) c WHERE NTF_YN != '1'
AND REQ_BUY_TYPE = #{reqBuyType}
AND STTUS_VAL = #{sttusVal}
AND COMMEND_YN = #{commendYn}
AND EVENT_CD = #{eventCd}
AND CONTRACT_NUM IN
#{item}
AND PROD_ID = #{prodId}
AND RATE_CD = #{rateCd}
AND LAST_BEST_REVIEW_CHK = 'Y'
AND SNS_INFO IS NOT NULL

SELECT ( SELECT COUNT(*) FROM MCP_REQUEST_REVIEW_ANSWER A, MCP_REVIEW_QUESTION_BAS B WHERE 1=1 AND A.QUESTION_ID = B.QUESTION_ID AND A.QUESTION_ID = #{questionId} AND A.CRET_DD BETWEEN NVL(B.STAT_START_DD, TO_DATE('20000101', 'YYYYMMDD')) AND NVL(B.STAT_END_DD, TO_CHAR(SYSDATE , 'YYYYMMDD'))
) AS TOTAL_CNT , A.ANSWER_DESC , SUM(CASE WHEN A.ANSWER_ID = B.ANSWER_ID THEN 1 ELSE 0 end) AS ANSWER_CNT , A.QUESTION_ID FROM MCP_REVIEW_QUESTION_DTL A, MCP_REQUEST_REVIEW_ANSWER B, MCP_REVIEW_QUESTION_BAS C, MCP_REQUEST_REVIEW D WHERE 1=1 AND A.QUESTION_ID = B.QUESTION_ID AND A.QUESTION_ID = C.QUESTION_ID AND B.REQUEST_KEY = D.REQUEST_KEY AND B.REVIEW_ID = D.REVIEW_ID AND A.QUESTION_ID = #{questionId} AND B.CRET_DD BETWEEN NVL(C.STAT_START_DD, TO_DATE('20000101', 'YYYYMMDD')) AND NVL(C.STAT_END_DD, TO_CHAR(SYSDATE , 'YYYYMMDD'))
AND D.EVENT_CD = #{eventCd}
GROUP BY A.ANSWER_ID,A.ANSWER_DESC,A.QUESTION_ID ORDER BY A.ANSWER_ID

